mapper.select:
SELECT i.id, i.stocktake_id, i.material_id, i.material_name, i.spec, i.unit, i.warehouse_id, w.warehouse_name, i.location_id, l.location_name, i.batch_no, i.inventory_id, i.expiry_date, i.system_qty, i.actual_qty, i.diff_qty, i.unit_cost, i.diff_amount, i.diff_type, i.diff_direction, i.diff_reason, i.recognition_source, i.ai_confidence, i.remark, i.line_remark, i.created_at, i.updated_at FROM wms_stocktake_order_item i INNER JOIN wms_stocktake_order o ON o.id = i.stocktake_id AND o.deleted = 0 LEFT JOIN wms_warehouse w ON w.id = i.warehouse_id AND w.deleted = 0 LEFT JOIN wms_location l ON l.id = i.location_id WHERE i.stocktake_id = #{stocktakeId}
AND o.org_id = #{orgId}
AND o.tenant_id = #{tenantId}
ORDER BY i.id

SELECT iv.id, iv.stocktake_id, iv.material_id, iv.material_name, iv.spec, iv.unit, iv.warehouse_id, w.warehouse_name, iv.location_id, l.location_name, iv.batch_no, iv.inventory_id, iv.expiry_date, iv.system_qty, iv.actual_qty, iv.diff_qty, iv.unit_cost, iv.diff_amount, iv.diff_type, iv.diff_direction, iv.diff_reason, iv.recognition_source, iv.ai_confidence, iv.remark, iv.line_remark, iv.created_at, iv.updated_at FROM wms_stocktake_order_item_version iv INNER JOIN wms_stocktake_order_version v ON v.id = iv.stocktake_version_id LEFT JOIN wms_warehouse w ON w.id = iv.warehouse_id AND w.deleted = 0 LEFT JOIN wms_location l ON l.id = iv.location_id WHERE iv.stocktake_id = #{stocktakeId} AND iv.version_no = #{versionNo}
AND v.org_id = #{orgId}
AND v.tenant_id = #{tenantId}
ORDER BY iv.id

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order_item i
    WHERE i.warehouse_id = #{warehouseId}
      AND EXISTS (
            SELECT 1
            FROM wms_stocktake_order o
            WHERE o.id = i.stocktake_id
              AND o.deleted = 0
              AND o.status IN
              #{status}
      )
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order_item
    WHERE warehouse_id = #{warehouseId}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order_item i
    WHERE i.location_id = #{locationId}
      AND EXISTS (
            SELECT 1
            FROM wms_stocktake_order o
            WHERE o.id = i.stocktake_id
              AND o.deleted = 0
              AND o.status IN
              #{status}
      )
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order_item
    WHERE location_id = #{locationId}
)
